const v10ReadA={id:"v10-read-a",kind:"passage",label:"Passage for Items 69-72",title:"Library Queue Tokens",description:"A city library used one line for borrowing, card registration, and research questions. Short transactions were often delayed behind complicated requests. The library tested numbered tokens in three categories and displayed the next token for each service desk. Average borrowing time fell, but visitors sometimes chose the wrong category. Staff then placed plain-language examples beside the token buttons and assigned a guide during busy hours. Wrong selections declined. The library kept a single priority lane for older persons, pregnant clients, and persons with disabilities instead of requiring them to choose a token category.",alt:"Passage about a library separating queue tokens by service, adding examples and a guide after visitors chose wrong categories, and retaining one priority lane for clients needing accommodation."};
const v10ReadB={id:"v10-read-b",kind:"passage",label:"Babasahin para sa Aytem 73-76",title:"Bantay-Tubig sa Paaralan",description:"Napansin ng isang paaralan na mataas ang konsumo ng tubig kahit walang klase tuwing Sabado. Sinuri ng pangkat ang buwanang metro ngunit hindi nito matukoy kung aling gusali ang may suliranin. Naglagay sila ng pansamantalang metro sa bawat gusali sa loob ng dalawang linggo. Lumitaw na tuloy-tuloy ang agos sa lumang palikuran malapit sa gym. Matapos palitan ang sirang balbula, bumaba ang konsumo sa katapusan ng linggo. Iminungkahi ng pangkat na ipagpatuloy ang hiwa-hiwalay na pagsukat kada quarter upang maagang makita ang mga tagas.",alt:"Teksto tungkol sa paaralang gumamit ng pansamantalang metro sa bawat gusali, natukoy ang sirang balbula sa lumang palikuran, at nagmungkahing ulitin ang hiwa-hiwalay na pagsukat kada quarter."};
const v10ReadC={id:"v10-read-c",kind:"passage",label:"Passage for Items 77-80",title:"Flexible Pickup Windows",description:"A records office initially told every applicant to collect documents between 1:00 and 3:00 p.m. The narrow window created a crowd soon after lunch, while the counter was nearly idle late in the day. The office divided completed documents into morning and afternoon pickup windows based on the applicant's selected preference. It also allowed authorized representatives who presented the required identification. Waiting time decreased, but applicants who missed their selected window still caused confusion. The office therefore added a clearly marked end-of-day period for missed pickups and monitored whether that period became congested.",alt:"Passage about a records office replacing one crowded pickup window with applicant-selected morning and afternoon windows, allowing authorized representatives, and adding a monitored end-of-day period for missed pickups."};
const v10DataA={id:"v10-data-a",kind:"table",label:"Table for Items 155-158",title:"Health Follow-up Referrals",description:"Residents referred, contacted, and completing a follow-up visit in four districts. Unit: residents.",headers:["District","Referred","Contacted","Completed visit"],rows:[["North",90,81,63],["East",75,72,60],["South",88,77,66],["West",70,63,56]],legend:["Contacted: referred residents successfully reached","Completed: contacted residents who attended a follow-up visit"],alt:"Table in residents. North: 90 referred, 81 contacted, 63 completed. East: 75, 72, 60. South: 88, 77, 66. West: 70, 63, 56."};
